#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n; scanf("%d", &n);
        long long *a = (long long*)malloc(n*sizeof(long long));
        long long mx = 0;
        for(int i=0;i<n;i++){
            scanf("%lld", &a[i]);
            if(a[i]>mx) mx=a[i];
        }
        int cnt=0;
        for(int i=0;i<n;i++) if(a[i]==mx) cnt++;
        int ops=0;
        int cur=cnt;
        while(cur<n){
            cur*=2;
            ops++;
        }
        printf("%d\n", ops);
        free(a);
    }
    return 0;
}

