    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int n; cin>>n;
        vector<long long> a(n);
        long long mx=0;
        for(int i=0;i<n;i++){
            cin>>a[i];
            mx=max(mx,a[i]);
        }
        int cnt=0;
        for(long long v: a) if(v==mx) cnt++;
        int ops=0;
        int cur=cnt;
        while(cur<n){
            cur*=2;
            ++ops;
        }
        cout<<ops<<"\n";
    }
    return 0;
}

